import numpy as np

def dilated_conv2d(x: np.ndarray, W: np.ndarray, b: np.ndarray,
                   dilation: int = 1, stride: int = 1,
                   padding: int = 0) -> np.ndarray:
    N, C_in, H, W_in = x.shape
    C_out, _, kH, kW = W.shape
    k_eff_h = kH + (kH - 1) * (dilation - 1)
    k_eff_w = kW + (kW - 1) * (dilation - 1)
    if padding > 0:
        x = np.pad(x, ((0,0),(0,0),(padding,padding),(padding,padding)))
    H_pad, W_pad = x.shape[2], x.shape[3]
    H_out = (H_pad - k_eff_h) // stride + 1
    W_out = (W_pad - k_eff_w) // stride + 1
    out = np.zeros((N, C_out, H_out, W_out), dtype=x.dtype)
    for n in range(N):
        for co in range(C_out):
            for i in range(H_out):
                for j in range(W_out):
                    val = 0.0
                    for ki in range(kH):
                        for kj in range(kW):
                            hi = i * stride + ki * dilation
                            wj = j * stride + kj * dilation
                            val += float(np.sum(x[n, :, hi, wj] * W[co, :, ki, kj]))
                    out[n, co, i, j] = val + b[co]
    return out
